USE LIVE
GO

SELECT RL.PACKLIST_ID
	, R.INVOICE_ID
	, R.INVOICE_DATE
	, R.CUSTOMER_ID
	, RL.CUST_ORDER_ID
	, RL.PACKLIST_LINE_NO
	, SL.CUST_ORDER_ID
	, R.TOTAL_AMOUNT
FROM RECEIVABLE R
INNER JOIN RECEIVABLE_LINE RL
	ON R.INVOICE_ID = RL.INVOICE_ID
INNER JOIN SHIPPER_LINE SL
	ON RL.PACKLIST_ID = SL.PACKLIST_ID
	AND RL.PACKLIST_LINE_NO = SL.LINE_NO
WHERE R.INVOICE_DATE >= '12/31/2019'
	AND RL.PACKLIST_ID IN ('1295525','1298533','1298534','1298049','1297731','1299278','1298909','1298390','1298918','1299233','1298874','1299559','1299219','1297060','1297061','1298471','1299218','1297054','1297055','1299205','1297059','1297056','1297048','1297051','1299486','1297044','1297053','1299421','1299588','1297754','1297755','1297050','1298474','1298575','1299230','1297062','1299232','1299229','1299416','1298594','1298593','1299224','1298539','1299403','1299578','1299222','1298381','1299418','1299414','1299437','1299057','1299557','1299410','1299056','1298538','1298406','1297064','1299227','1298395','1298782','1299411','1299453','1299234','1299413','1299231','1299405','1299427','1298785','1299582','1299554','1299416','1299221','1299052','1299409','1298592','1298571','1299428','1299216','1299135','1299448','1299448','1298119','1299235','1297065','1298541','1299410','1299422','1298784','1299552','1298788','1299408','1299573','1299556','1299447','1298102','1299217','1298514','1291611','1299574','1299445','1298792','1299237','1299225','1297747','1299563','1299209','1299210','1299424','1299558','1298841','1299302','1299207','1299236','1299213','1299572','1299211','1298546','1299564','1298577','1298920','1299451','1299553','1299083','1299579','1298923','1299277','1299223','1299058','1299208','1299438','1298553','1298777','1299501','1298731','1299741','1298552','1298584','1298583','1298586','1298913','1297723','1297744','1299436','1299228','1299050','1299565','1299575','1299214','1298506','1297724','1298391','1298515','1298369','464336','1297725','1299426','1299212','1298797','1298529','1298796','1299452','1299214','1297746','1298793','1299049','1298530','1299215','1297745','1299049','1298516','1298517')